/// State for epoch-aware select combinator.
#[derive(Debug)]
pub struct EpochSelectState<T, const N: usize> {
    /// Underlying select state.
    inner: SelectState<T, N>,

    /// Epoch context.
    epoch_ctx: EpochContext,

    /// Policy.
    policy: EpochPolicy,
}

impl<T, const N: usize> EpochSelectState<T, N> {
    /// Creates a new epoch-aware select state.
    pub fn new(epoch_ctx: EpochContext, policy: EpochPolicy) -> Self {
        Self {
            inner: SelectState::new(),
            epoch_ctx,
            policy,
        }
    }

    /// Checks epoch validity.
    pub fn check_epoch(&self, now: Time) -> Result<(), EpochError> {
        if self.policy.on_transition == EpochTransitionBehavior::Ignore {
            return Ok(());
        }

        if self.epoch_ctx.is_expired(now) {
            return Err(EpochError::Expired {
                epoch: self.epoch_ctx.epoch_id,
            });
        }

        Ok(())
    }

    /// Gets the epoch context for propagation to branches.
    pub fn epoch_context(&self) -> &EpochContext {
        &self.epoch_ctx
    }
}

